// Solution
function calculate(a, operator, b) {
  switch (operator) {
    case '+':
      return (parseInt(a) + parseInt(b)).toString();
    case '-':
      return (parseInt(a) - parseInt(b)).toString();
    case '*':
      return (parseInt(a) * parseInt(b)).toString();
    case '/':
      if (parseInt(b) === 0) {
        return 'Error: Division by zero';
      } else {
        return (parseInt(a) / parseInt(b)).toString();
      }
    default:
      return 'Error: Invalid operator';
  }
}

