// Solution
class Solution:
  def calculate(self, s):
    a, operator, b = s.split(' ')
    if operator == '+':
      return str(int(a) + int(b))
    elif operator == '-':
      return str(int(a) - int(b))
    elif operator == '*':
      return str(int(a) * int(b))
    elif operator == '/':
      if int(b) == 0:
        return 'Error: Division by zero'
      else:
        return str(int(a) / int(b))
    else:
      return 'Error: Invalid operator'
